detaileddescription.para:
Example usage: #include<zephyr/drivers/misc/max2221x/max2221x.h>

intret=max2221x_set_master_chop_freq(dev,MAX2221X_FREQ_50KHZ);
if(ret)
printk("Failedtosetmasterchopfrequency:%d\n",ret);
else
printk("Masterchopfrequencysetsuccessfully\n");

Example usage: #include<zephyr/drivers/misc/max2221x/max2221x.h>

intret=max2221x_mask_fault_pin(dev,MAX2221X_FAULT_PIN_OCP);
if(ret)
printk("Failedtomaskfaultpin:%d\n",ret);
else
printk("Faultpinmaskedsuccessfully\n");

Example usage: #include<zephyr/drivers/misc/max2221x/max2221x.h>

intret=max2221x_unmask_fault_pin(dev,MAX2221X_FAULT_PIN_OCP);
if(ret)
printk("Failedtounmaskfaultpin:%d\n",ret);
else
printk("Faultpinunmaskedsuccessfully\n");

