Example usage: #include<zephyr/drivers/misc/max2221x/max2221x.h>

intret=max2221x_set_snsf(dev,1,MAX2221X_SNSF_2_3);
if(ret)
printk("Failedtosetsensescalingfactor:%d\n",ret);
else
printk("Sensescalingfactorsetsuccessfully\n");

Usually, set on time, off time, repetitions, and stop state before starting rapid fire mode.

Example usage: #include<zephyr/drivers/misc/max2221x/max2221x.h>

intret;
ret=max2221x_set_on_time(dev,channel,1000);
if(ret){
printk("Failedtosetontime:%d\n",ret);
returnret;
}
ret=max2221x_set_off_time(dev,channel,1000);
if(ret){
printk("Failedtosetofftime:%d\n",ret);
returnret;
}
ret=max2221x_set_stop_state(dev,channel,true);
if(ret){
printk("Failedtosetstopstate:%d\n",ret);
returnret;
}
ret=max2221x_set_repetitions(dev,channel,10);
if(ret){
printk("Failedtosetrepetitions:%d\n",ret);
returnret;
}
ret=max2221x_start_rapid_fire(dev,channel);
if(ret){
printk("Failedtostartrapidfiremode:%d\n",ret);
}else{
printk("Rapidfiremodestartedsuccessfully\n");
}
